sql:
SELECT loan_id, term
FROM loans
WHERE risk_score > (SELECT AVG(risk_score) FROM loans);

SELECT loan_id, loan_amount
FROM loans
WHERE risk_score > 700 AND grade IN ('A', 'B', 'C');

SELECT AVG(risk_score) AS average_risk_score
FROM loans
WHERE funded_amount > 100000;

SELECT *
FROM loans
WHERE risk_score = (SELECT MAX(risk_score) FROM loans);

external_knowledge:
- "Have flown above the stormy seas of 10% interest" means the interest rate on the loans is greater than 10%;
- "Reveal the identities" refers to the names of the borrowers;
- "Length of their voyages" refers to the term of the loan;
- "Financial waters they navigated" refers to the loan amount and interest rate;
- "Treasures they sought with their loans" refers to the purpose of the loans.

